from pathlib import Path
base=Path('solver.py').read_text()
out=Path('runs/low_model_candidates'); out.mkdir(exist_ok=True)
old="def _pick_low_robust_best(solutions,candidates,all_tasks):\n\tB=all_tasks;A=candidates;D=[A for A in solutions if A]\n\tif not D:return[]\n\tE=min(D,key=lambda s:_solution_expected_cost(s,A,B));C=_solution_expected_cost(E,A,B)\n\tdef G(solution):E=solution;D=_solution_expected_cost(E,A,B);F=_solution_expected_cost_by_model(E,A,B,_L);G=_solution_expected_cost_by_model(E,A,B,_M);H=.45*D+.45*F+.1*G;I=max(D-C,F-C,G-C);return H+.15*max(_C,I),max(D,F,G),D\n\tF=min(D,key=G);H=_solution_expected_cost(F,A,B)\n\tif H<=C+25.:return F\n\treturn E"
models={
 'low_pick_min_score_strict': "def _pick_low_robust_best(solutions,candidates,all_tasks):\n\tB=all_tasks;A=candidates;D=[A for A in solutions if A]\n\tif not D:return[]\n\tE=min(D,key=lambda s:_solution_expected_cost(s,A,B));C=_solution_expected_cost(E,A,B)\n\tF=min(D,key=lambda s:(_solution_expected_cost_by_model(s,A,B,_L),_solution_expected_cost(s,A,B)))\n\tH=_solution_expected_cost(F,A,B)\n\tif H<=C+15.:return F\n\treturn E",
 'low_pick_min_score_loose': "def _pick_low_robust_best(solutions,candidates,all_tasks):\n\tB=all_tasks;A=candidates;D=[A for A in solutions if A]\n\tif not D:return[]\n\tE=min(D,key=lambda s:_solution_expected_cost(s,A,B));C=_solution_expected_cost(E,A,B)\n\tF=min(D,key=lambda s:(_solution_expected_cost_by_model(s,A,B,_L),_solution_expected_cost(s,A,B)))\n\tH=_solution_expected_cost(F,A,B)\n\tif H<=C+45.:return F\n\treturn E",
 'low_pick_minmax': "def _pick_low_robust_best(solutions,candidates,all_tasks):\n\tB=all_tasks;A=candidates;D=[A for A in solutions if A]\n\tif not D:return[]\n\tE=min(D,key=lambda s:_solution_expected_cost(s,A,B));C=_solution_expected_cost(E,A,B)\n\tF=min(D,key=lambda s:(max(_solution_expected_cost(s,A,B),_solution_expected_cost_by_model(s,A,B,_L),_solution_expected_cost_by_model(s,A,B,_M)),_solution_expected_cost(s,A,B)))\n\tH=_solution_expected_cost(F,A,B)\n\tif H<=C+30.:return F\n\treturn E",
 'low_pick_min_score_shape': "def _pick_low_robust_best(solutions,candidates,all_tasks):\n\tB=all_tasks;A=candidates;D=[A for A in solutions if A]\n\tif not D:return[]\n\tE=min(D,key=lambda s:_solution_expected_cost(s,A,B));C=_solution_expected_cost(E,A,B);R={(a[0],a[2]):a for a in A}\n\tdef S(sol):\n\t\tpen=_C\n\t\tfor k,cs in sol:\n\t\t\trows=[R.get((k,c)) for c in cs];rows=[r for r in rows if r is not _A]\n\t\t\tif not rows:pen+=100.;continue\n\t\t\tpen+=2.*abs(len(rows)-2)+5.*max(0,len(rows[0][1])-1)\n\t\treturn _solution_expected_cost_by_model(sol,A,B,_L)+pen\n\tF=min(D,key=lambda s:(S(s),_solution_expected_cost(s,A,B)))\n\tH=_solution_expected_cost(F,A,B)\n\tif H<=C+25.:return F\n\treturn E",
}
if old not in base: raise SystemExit('old picker pattern not found')
for name,new in models.items():
    p=out/(name+'.py'); p.write_text(base.replace(old,new)); print(p)
